import cv2
import numpy as np
from flask import Flask, jsonify
from sklearn.neighbors import KNeighborsClassifier

app = Flask(__name__)

# Load Haar Cascade Classifier for face detection
face_cascade = cv2.CascadeClassifier(cv2.data.haarcascades + 'haarcascade_frontalface_default.xml')

# Load trained kNN model
knn_model = KNeighborsClassifier(n_neighbors=5)

def detect_faces_and_predict(image):
    gray_image = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
    faces = face_cascade.detectMultiScale(gray_image, scaleFactor=1.3, minNeighbors=5)

    predictions = []
    for (x, y, w, h) in faces:
        face_region = gray_image[y:y+h, x:x+w]
        prediction = knn_model.predict(face_region.reshape(-1, face_region.shape[0] * face_region.shape[1]))
        predictions.append(prediction)

    return np.array(predictions)

@app.route('/api/recognize', methods=['POST'])
def recognize():
    if request.method == 'POST':
        img = request.files['image']
        img_array = np.array(bytearray(img.read()), dtype='uint8')
        img_array = cv2.imdecode(img_array, cv2.IMREAD_COLOR)
        results = detect_faces_and_predict(img_array)

        # For each face, calculate the probability distribution over all known classes
        confidences = []
        for result in results:
            class_confidences = np.bincount(result).astype('float') / len(result)
            confidences.append(class_confidences)

        return jsonify({"confidences": [dict(zip(employee_names, confidence)) for confidence in confidences]})

if __name__ == "__main__":
    app.run(debug=True)